import React from "react";
import { useNavigate } from "react-router-dom";

function RoleSelector() {
  const navigate = useNavigate();
  return (
    <div className="flex flex-col items-center justify-center h-64 space-y-4">
      <h2 className="text-2xl font-bold">Select Your Role</h2>
      <div className="space-x-4">
        <button onClick={() => navigate("/customer")} className="bg-purple-500 text-white px-4 py-2 rounded">Customer</button>
        <button onClick={() => navigate("/admin")} className="bg-purple-500 text-white px-4 py-2 rounded">Admin</button>
        <button onClick={() => navigate("/driver")} className="bg-purple-500 text-white px-4 py-2 rounded">Driver</button>
        <button onClick={() => navigate("/uploader")} className="bg-purple-500 text-white px-4 py-2 rounded">Uploader</button>
      </div>
    </div>
  );
}

export default RoleSelector;
